#include<bits/stdc++.h>
using namespace std;
class Solution {
public:
    int lengthOfLongestSubstring(string s) {
        int hash[26]={0};unordered_map<char,int>mpp;
        int max=0;  
        string str;
        int l=0,r=0;int x=s.size();
        for(int i=0;i<x;i++)
        {
            if(s[i]==' ')
           {s.erase(i,1);max++;}

        }
        while(r<s.size()){

            hash[s[r]-'a']++;
            if(hash[s[r]-'a']>1)
            {
                int x=mpp[s[r]];
                if(r-l>max)
                {max=r-l;str=s.substr(l,max);}
                for(int i=l;i<=x;i++)
                hash[s[i]-'a']--;;
            
                l=x+1;
            }
           
            
             mpp[s[r]]=r;  r++;
            if(r<=l)
                r=l+1;
            
       
        }
        
        cout<<max<<endl;
        
    }
        
    
};
